        app_db = appsdb.ApplicationsDatabase()

        apps_to_backup = self._config.apps_to_sync or app_db.get_app_names()

        for app_name in self._config.apps_to_ignore:
            apps_to_backup.discard(app_name)

        return apps_to_backup

